// Helper functions
function getPlanLimit($plan, $type) {
    $limits = PLAN_LIMITS[$plan] ?? PLAN_LIMITS['starter'];
    return $limits[$type] ?? 0;
}

function getPinPrice($plan) {
    return PIN_PRICES[$plan] ?? PIN_PRICES['starter'];
}